// Calculate Task Priority Score using weighted formula from Workflow Configuration

// Access configuration weights
const config = $('Workflow Configuration').first().json;
const urgencyWeight = config.taskPriorityWeightUrgency;
const workloadWeight = config.taskPriorityWeightWorkload;
const skillMatchWeight = config.taskPriorityWeightSkillMatch;

// Get current item data
const taskAssignments = $input.item.json.task_assignments || [];

// Calculate priority scores for each task assignment
const enrichedAssignments = taskAssignments.map(task => {
  // Extract task metrics (normalize to 0-1 scale if needed)
  const urgency = task.urgency || 0;
  const workload = task.workload || 0;
  const skillMatch = task.skill_match || 0;

  // Calculate weighted priority score
  const priorityScore = (
    (urgency * urgencyWeight) +
    (workload * workloadWeight) +
    (skillMatch * skillMatchWeight)
  );

  // Return enriched task with calculated priority score
  return {
    ...task,
    priority_score: Math.round(priorityScore * 1000) / 1000, // Round to 3 decimal places
    calculation_metadata: {
      urgency_weight: urgencyWeight,
      workload_weight: workloadWeight,
      skill_match_weight: skillMatchWeight,
      calculated_at: new Date().toISOString()
    }
  };
});

// Return the item with enriched task assignments
return {
  json: {
    ...$input.item.json,
    task_assignments: enrichedAssignments,
    priority_calculation_complete: true
  }
};

// Mask PII and PHI Data
// This code sanitizes sensitive information while preserving data structure

const crypto = require('crypto');

// Helper function to hash sensitive data
function hashValue(value) {
  if (!value) return value;
  return crypto.createHash('sha256').update(String(value)).digest('hex').substring(0, 16);
}

// Helper function to mask SSN (XXX-XX-1234)
function maskSSN(ssn) {
  if (!ssn) return ssn;
  const cleaned = String(ssn).replace(/\D/g, '');
  if (cleaned.length === 9) {
    return `XXX-XX-${cleaned.substring(5)}`;
  }
  return 'XXX-XX-XXXX';
}

// Helper function to mask credit card (XXXX-XXXX-XXXX-1234)
function maskCreditCard(cc) {
  if (!cc) return cc;
  const cleaned = String(cc).replace(/\D/g, '');
  if (cleaned.length >= 13 && cleaned.length <= 16) {
    return `XXXX-XXXX-XXXX-${cleaned.substring(cleaned.length - 4)}`;
  }
  return 'XXXX-XXXX-XXXX-XXXX';
}

// Helper function to mask patient names
function maskName(name) {
  if (!name) return name;
  const parts = String(name).split(' ');
  return parts.map(part => {
    if (part.length <= 1) return part;
    return part[0] + '*'.repeat(part.length - 1);
  }).join(' ');
}

// Helper function to recursively sanitize objects
function sanitizeObject(obj) {
  if (obj === null || obj === undefined) return obj;

  if (Array.isArray(obj)) {
    return obj.map(item => sanitizeObject(item));
  }

  if (typeof obj === 'object') {
    const sanitized = {};

    for (const [key, value] of Object.entries(obj)) {
      const lowerKey = key.toLowerCase();

      // Mask SSN fields
      if (lowerKey.includes('ssn') || lowerKey.includes('social_security')) {
        sanitized[key] = maskSSN(value);
      }
      // Mask credit card fields
      else if (lowerKey.includes('credit_card') || lowerKey.includes('card_number') || lowerKey.includes('cc_number')) {
        sanitized[key] = maskCreditCard(value);
      }
      // Mask patient name fields
      else if (lowerKey.includes('patient_name') || lowerKey.includes('name') && lowerKey.includes('patient')) {
        sanitized[key] = maskName(value);
      }
      // Hash patient IDs and other sensitive identifiers
      else if (lowerKey.includes('patient_id') || lowerKey.includes('mrn') || lowerKey.includes('medical_record')) {
        sanitized[key] = `HASH_${hashValue(value)}`;
      }
      // Mask email addresses (keep domain)
      else if (lowerKey.includes('email') && typeof value === 'string' && value.includes('@')) {
        const [local, domain] = value.split('@');
        sanitized[key] = `${local[0]}${'*'.repeat(Math.max(local.length - 1, 3))}@${domain}`;
      }
      // Mask phone numbers (keep last 4 digits)
      else if (lowerKey.includes('phone') || lowerKey.includes('mobile')) {
        const cleaned = String(value).replace(/\D/g, '');
        if (cleaned.length >= 10) {
          sanitized[key] = `XXX-XXX-${cleaned.substring(cleaned.length - 4)}`;
        } else {
          sanitized[key] = 'XXX-XXX-XXXX';
        }
      }
      // Recursively sanitize nested objects and arrays
      else if (typeof value === 'object') {
        sanitized[key] = sanitizeObject(value);
      }
      // Keep other values as-is
      else {
        sanitized[key] = value;
      }
    }

    return sanitized;
  }

  return obj;
}

// Process all input items
const sanitizedItems = $input.all().map(item => {
  return {
    json: sanitizeObject(item.json),
    pairedItem: item.pairedItem
  };
});

return sanitizedItems;
